import{_ as e,o as d,c as o,ae as a}from"./chunks/framework.DTwQaIIa.js";const b=JSON.parse('{"title":"快速开始","description":"","frontmatter":{},"headers":[],"relativePath":"guide/getting-started.md","filePath":"guide/getting-started.md"}'),i={name:"guide/getting-started.md"};function r(c,t,l,n,s,h){return d(),o("div",null,[...t[0]||(t[0]=[a('<h1 id="快速开始" tabindex="-1">快速开始 <a class="header-anchor" href="#快速开始" aria-label="Permalink to &quot;快速开始&quot;">​</a></h1><h2 id="环境要求" tabindex="-1">环境要求 <a class="header-anchor" href="#环境要求" aria-label="Permalink to &quot;环境要求&quot;">​</a></h2><table tabindex="0"><thead><tr><th>项目</th><th>要求</th></tr></thead><tbody><tr><td>Java</td><td><code>25</code> 或更高（推荐 GraalVM）</td></tr><tr><td>服务端</td><td>Spigot 1.21+（或兼容分支如 Paper）</td></tr><tr><td>运行库</td><td>Adventure、exp4j、BoostedYaml（由 CoreLib 通过 <code>plugin.yml libraries</code> 自动加载）</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">提示</p><p>首次部署 <code>EmakiCoreLib 3.3.0</code> 时，确认服务端允许通过 <code>plugin.yml libraries</code> 下载运行库。部分服务端或网络环境可能会阻止自动下载——如果遇到这种情况，需要提前把对应的运行库 jar 放到服务端的 <code>libraries/</code> 缓存目录里。</p></div><h2 id="推荐启用顺序" tabindex="-1">推荐启用顺序 <a class="header-anchor" href="#推荐启用顺序" aria-label="Permalink to &quot;推荐启用顺序&quot;">​</a></h2><p>模块之间有依赖关系，一次性全部丢进去虽然也能跑，但出了问题很难定位。建议按下面的顺序逐步启用，每一步确认没问题再往下走：</p><h3 id="第一步-基础设施与属性层" tabindex="-1">第一步：基础设施与属性层 <a class="header-anchor" href="#第一步-基础设施与属性层" aria-label="Permalink to &quot;第一步：基础设施与属性层&quot;">​</a></h3><ol><li><strong>EmakiCoreLib</strong> — 所有模块的强依赖，必须最先装</li><li><strong>EmakiAttribute</strong> — 属性与战斗系统，后续的锻造、强化、宝石都会往物品上写属性，Attribute 负责读取和计算这些数值</li></ol><p>验证要点：CoreLib 正常加载（控制台无报错），Attribute 的属性定义能被识别、战斗伤害计算正常。</p><h3 id="第二步-装备成长闭环" tabindex="-1">第二步：装备成长闭环 <a class="header-anchor" href="#第二步-装备成长闭环" aria-label="Permalink to &quot;第二步：装备成长闭环&quot;">​</a></h3><ol start="3"><li><strong>EmakiForge</strong> — 锻造系统</li><li><strong>EmakiStrengthen</strong> — 强化系统</li></ol><p>这两个模块构成装备的&quot;制造 → 强化&quot;闭环。验证要点：锻造配方能正常执行并产出物品，强化流程和星级成长正常运作。</p><h3 id="第三步-世界交互与镶嵌成长线" tabindex="-1">第三步：世界交互与镶嵌成长线 <a class="header-anchor" href="#第三步-世界交互与镶嵌成长线" aria-label="Permalink to &quot;第三步：世界交互与镶嵌成长线&quot;">​</a></h3><ol start="5"><li><strong>EmakiGem</strong> — 宝石系统</li><li><strong>EmakiCooking</strong> — 烹饪系统</li></ol><p>验证要点：宝石的镶嵌、提取、升级流程跑通，烹饪工位在世界中可正常交互。</p><h3 id="第四步-主动技能线" tabindex="-1">第四步：主动技能线 <a class="header-anchor" href="#第四步-主动技能线" aria-label="Permalink to &quot;第四步：主动技能线&quot;">​</a></h3><ol start="7"><li><strong>EmakiSkills</strong> + MythicMobs 内容包</li></ol><div class="warning custom-block"><p class="custom-block-title">注意</p><p>EmakiSkills 只负责技能的管理（解锁、槽位、触发、施法模式），技能的实际效果由 MythicMobs 配置定义。没装 MythicMobs 的话 Skills 本身能启动，但玩家释放技能时不会有任何效果。</p></div><h2 id="模块依赖矩阵" tabindex="-1">模块依赖矩阵 <a class="header-anchor" href="#模块依赖矩阵" aria-label="Permalink to &quot;模块依赖矩阵&quot;">​</a></h2><table tabindex="0"><thead><tr><th>模块</th><th>强依赖</th><th>软依赖</th></tr></thead><tbody><tr><td>EmakiCoreLib</td><td>—</td><td>Vault, ExcellentEconomy, PlaceholderAPI, MMOItems, ItemsAdder, Nexo, NeigeItems, CraftEngine</td></tr><tr><td>EmakiAttribute</td><td>EmakiCoreLib</td><td>MythicMobs, PlaceholderAPI, MMOItems</td></tr><tr><td>EmakiForge</td><td>EmakiCoreLib</td><td>EmakiAttribute, PlaceholderAPI</td></tr><tr><td>EmakiStrengthen</td><td>EmakiCoreLib</td><td>EmakiAttribute, PlaceholderAPI</td></tr><tr><td>EmakiCooking</td><td>EmakiCoreLib</td><td>CraftEngine</td></tr><tr><td>EmakiGem</td><td>EmakiCoreLib</td><td>EmakiAttribute, PlaceholderAPI</td></tr><tr><td>EmakiSkills</td><td>EmakiCoreLib</td><td>MythicMobs, EmakiAttribute, PlaceholderAPI</td></tr></tbody></table><p>强依赖意味着没装就无法启动；软依赖是&quot;有就用，没有也能跑&quot;——比如不装 EmakiAttribute，Forge 照样能锻造物品，只是产物不会携带属性数据。</p><h2 id="命令速查" tabindex="-1">命令速查 <a class="header-anchor" href="#命令速查" aria-label="Permalink to &quot;命令速查&quot;">​</a></h2><table tabindex="0"><thead><tr><th>模块</th><th>根命令</th><th>别名</th></tr></thead><tbody><tr><td>EmakiAttribute</td><td><code>/emakiattribute</code></td><td><code>/eattribute</code>, <code>/ea</code></td></tr><tr><td>EmakiForge</td><td><code>/emakiforge</code></td><td><code>/eforge</code>, <code>/ef</code></td></tr><tr><td>EmakiStrengthen</td><td><code>/emakistrengthen</code></td><td><code>/estrengthen</code></td></tr><tr><td>EmakiCooking</td><td><code>/ecooking</code></td><td><code>/ec</code></td></tr><tr><td>EmakiGem</td><td><code>/emakigem</code></td><td><code>/egem</code>, <code>/eg</code></td></tr><tr><td>EmakiSkills</td><td><code>/emakiskills</code></td><td><code>/eskills</code></td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">提示</p><p>所有模块的根命令都支持 <code>reload</code> 子命令来热重载配置。重载时会刷新在线玩家的物品数据和 GUI 会话，不需要重启服务端。</p></div><h2 id="默认资源定位" tabindex="-1">默认资源定位 <a class="header-anchor" href="#默认资源定位" aria-label="Permalink to &quot;默认资源定位&quot;">​</a></h2><p>各模块首次启动时会自动把默认配置和资源文件释放到 <code>plugins/&lt;模块名&gt;/</code> 目录下。如果你需要自定义，直接在这些文件上改就行——重载时会读取你修改后的版本，不会覆盖。</p><table tabindex="0"><thead><tr><th>模块</th><th>主要资源目录</th></tr></thead><tbody><tr><td>EmakiCoreLib</td><td><code>config.yml</code>, <code>lang/</code></td></tr><tr><td>EmakiAttribute</td><td><code>attributes/</code>, <code>conditions/</code>, <code>damage_types/</code>, <code>lore_formats/</code>, <code>profiles/</code>, <code>config.yml</code></td></tr><tr><td>EmakiForge</td><td><code>recipes/</code>, <code>gui/</code>, <code>lang/</code>, <code>config.yml</code></td></tr><tr><td>EmakiStrengthen</td><td><code>recipes/</code>, <code>gui/</code>, <code>lang/</code>, <code>config.yml</code></td></tr><tr><td>EmakiCooking</td><td><code>recipes/</code>, <code>gui/</code>, <code>lang/</code>, <code>item_adjustments/</code>, <code>config.yml</code></td></tr><tr><td>EmakiGem</td><td><code>gems/</code>, <code>items/</code>, <code>gui/</code>, <code>conditions/</code>, <code>lang/</code>, <code>config.yml</code></td></tr><tr><td>EmakiSkills</td><td><code>skills/</code>, <code>resources/</code>, <code>gui/</code>, <code>lang/</code>, <code>config.yml</code></td></tr></tbody></table><h2 id="升级注意事项" tabindex="-1">升级注意事项 <a class="header-anchor" href="#升级注意事项" aria-label="Permalink to &quot;升级注意事项&quot;">​</a></h2><ul><li>升级前务必备份自定义配置、语言文件和默认资源副本</li><li>所有自定义的原版物品/方块来源需要迁移到 <code>minecraft-xxx</code>、<code>mc-xxx</code>、<code>v-xxx</code> 或裸 ID 写法（旧的 <code>minecraft:xxx</code> 格式不再被识别）</li><li>自定义展示需要迁移到 <code>structured_presentation</code>（旧的 <code>presentation</code>、<code>name_operations</code>、<code>lore_operations</code> 等已不再是受支持的主路径）</li><li>详细的版本变更和迁移指南见 <a href="/Emaki_Series/guide/changelog.html">更新日志</a></li></ul>',29)])])}const g=e(i,[["render",r]]);export{b as __pageData,g as default};
